INSERT INTO `community_qna` (`user_id`, `username`, `title`, `body`, `status`, `created_at`) VALUES ((SELECT id FROM users WHERE username = 'railvortex'), 'railvortex', 'Best wheels for rough asphalt?', 'I mostly skate street and the roads here are terrible. Are Spitfire 80HDs or Bones Rough Riders better?', 'approved', '2026-04-26 20:51:04');
INSERT INTO `community_qna` (`user_id`, `username`, `title`, `body`, `status`, `created_at`) VALUES ((SELECT id FROM users WHERE username = 'brokenboardclub'), 'brokenboardclub', 'Thunder vs Indy trucks?', 'Getting a new setup. I hear Indys turn better but Thunders are lighter. Thoughts?', 'approved', '2026-05-06 20:51:04');
INSERT INTO `community_qna` (`user_id`, `username`, `title`, `body`, `status`, `created_at`) VALUES ((SELECT id FROM users WHERE username = 'staticshred'), 'staticshred', 'How to stop razor tail?', 'I keep wearing down my tail super fast. Is there any trick to prevent this or do I just need to stop dragging?', 'approved', '2026-04-21 20:51:04');
INSERT INTO `community_qna` (`user_id`, `username`, `title`, `body`, `status`, `created_at`) VALUES ((SELECT id FROM users WHERE username = 'rampnomads'), 'rampnomads', 'Shoe recommendations for wide feet?', 'Every skate shoe I buy pinches my toes. Anyone know brands that fit wider?', 'approved', '2026-04-22 20:51:04');
INSERT INTO `community_qna` (`user_id`, `username`, `title`, `body`, `status`, `created_at`) VALUES ((SELECT id FROM users WHERE username = 'brokenrails'), 'brokenrails', 'First time at a skatepark, any advice?', 'Going to my local park tomorrow morning. Kind of nervous. What are the unwritten rules?', 'approved', '2026-05-05 20:51:04');
INSERT INTO `community_qna` (`user_id`, `username`, `title`, `body`, `status`, `created_at`) VALUES ((SELECT id FROM users WHERE username = 'velocitydeck'), 'velocitydeck', 'Deck sizes for street skating', 'Is 8.25 too wide for technical street tricks? I currently ride an 8.0.', 'approved', '2026-04-17 20:51:04');
INSERT INTO `community_qna` (`user_id`, `username`, `title`, `body`, `status`, `created_at`) VALUES ((SELECT id FROM users WHERE username = 'plankrebel'), 'plankrebel', 'Cleaning bearings', 'Can I use WD-40 to clean my bearings or will that ruin them?', 'approved', '2026-04-25 20:51:04');
INSERT INTO `community_shoutouts` (`user_id`, `username`, `title`, `body`, `status`, `created_at`) VALUES ((SELECT id FROM users WHERE username = 'asphaltphantom'), 'asphaltphantom', 'Landed my first kickflip!', 'Took me 3 months but I finally got it rolling. So hyped right now!', 'approved', '2026-05-13 20:51:04');
